def age_description(self) -> str:
        d = self.days_ago
        if d < 0:
            return "unknown age"
        if d == 0:
            return "introduced today"
        if d == 1:
            return "introduced yesterday"
        if d < 7:
            return f"introduced {d} days ago"
        if d < 30:
            return f"introduced {d // 7} week(s) ago"
        if d < 365:
            return f"introduced {d // 30} month(s) ago"
        return f"introduced {d // 365} year(s) ago"

def clean(self) -> bool:
        """True only if everything passed with zero errors."""
        return self.runnable and self.failed == 0 and self.errors == 0

def llm_available(self) -> bool:
        if self.llm_provider == "llamacpp":
            return True
        if self.llm_provider == "anthropic":
            return bool(self.api_key)
        if self.llm_provider == "groq":
            return bool(self.groq_api_key)
        if self.llm_provider == "ollama":
            return True
        return False

def _cosine_similarity(a: np.ndarray, b: np.ndarray) -> float:
        """
        Compute cosine similarity between two vectors.
        Returns 0.0 if either vector has zero magnitude.
        """
        norm = np.linalg.norm(a) * np.linalg.norm(b)
        if norm == 0.0:
            return 0.0
        return float(np.dot(a, b) / norm)

